import React, { useState } from 'react';
import './ClientForm.css';

const ClientForm = ({ onSuccess }) => {
  const [formData, setFormData] = useState({
    codeCli: '',
    nomCli: '',
    prenomCli: '',
    adressCli: '',
    telCli: '',
    sexe: ''
  });
  const [isEditing, setIsEditing] = useState(false);
  const [error, setError] = useState('');

  // ✅ Validation des champs
  const validateClientForm = (formData) => {
    const onlyLetters = /^[A-Za-zÀ-ÿ\s\-']+$/;
    const onlyDigits = /^[0-9]+$/;

    if (!onlyLetters.test(formData.nomCli)) {
      return 'Le nom ne doit contenir que des lettres';
    }
    if (!onlyLetters.test(formData.prenomCli)) {
      return 'Le prénom ne doit contenir que des lettres';
    }
    if (!onlyLetters.test(formData.adressCli)) {
      return 'L’adresse ne doit contenir que des lettres';
    }
    if (!onlyLetters.test(formData.sexe)) {
      return 'Le sexe ne doit contenir que des lettres';
    }
    if (!onlyDigits.test(formData.telCli)) {
      return 'Le numéro de téléphone ne doit contenir que des chiffres';
    }

    return null;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSearch = async () => {
    if (!formData.codeCli) {
      setError('Veuillez entrer un code client');
      return;
    }
    try {
      const res = await fetch(`http://localhost:3001/clients/${formData.codeCli}`);
      if (res.status === 404) {
        setError('Client non trouvé');
        setIsEditing(false);
        setFormData(prev => ({
          ...prev,
          nomCli: '',
          prenomCli: '',
          adressCli: '',
          telCli: '',
          sexe: ''
        }));
        return;
      }
      if (!res.ok) throw new Error('Erreur serveur');

      const data = await res.json();
      setFormData(data);
      setIsEditing(true);
      setError('');
    } catch (err) {
      setError(err.message);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    const validationError = validateClientForm(formData);
    if (validationError) {
      setError(validationError);
      return;
    }

    const { codeCli, nomCli, prenomCli, adressCli, telCli, sexe } = formData;

    try {
      const method = isEditing ? 'PUT' : 'POST';
      const url = isEditing
        ? `http://localhost:3001/clients/${codeCli}`
        : 'http://localhost:3001/clients';

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nomCli, prenomCli, adressCli, telCli, sexe })
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      if (!isEditing) {
        setFormData({
          codeCli: '',
          nomCli: '',
          prenomCli: '',
          adressCli: '',
          telCli: '',
          sexe: ''
        });
      }

      setIsEditing(false);
      if (onSuccess) onSuccess();
      alert(isEditing ? 'Client modifié avec succès' : 'Client ajouté avec succès');
    } catch (err) {
      setError(err.message);
    }
  };

  const handleDelete = async () => {
    if (!isEditing) return;

    const confirmDelete = window.confirm('Supprimer ce client ?');
    if (!confirmDelete) return;

    try {
      const res = await fetch(`http://localhost:3001/clients/${formData.codeCli}`, {
        method: 'DELETE'
      });
      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      setFormData({
        codeCli: '',
        nomCli: '',
        prenomCli: '',
        adressCli: '',
        telCli: '',
        sexe: ''
      });
      setIsEditing(false);
      if (onSuccess) onSuccess();
      alert('Client supprimé avec succès');
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div className="client-form-container">
      <h2>{isEditing ? 'Modifier Client' : 'Ajouter Client'}</h2>

      <div className="search-block">
        <input
          type="number"
          name="codeCli"
          placeholder="Code client"
          value={formData.codeCli}
          onChange={handleChange}
          className="input-codeCli"
        />
        <button type="button" onClick={handleSearch} className="btn-search">
          Rechercher
        </button>
      </div>

      <form onSubmit={handleSubmit}>
        <input
          name="nomCli"
          placeholder="Nom"
          value={formData.nomCli}
          onChange={handleChange}
          required
          className="form-input"
        />
        <input
          name="prenomCli"
          placeholder="Prénom"
          value={formData.prenomCli}
          onChange={handleChange}
          required
          className="form-input"
        />
        <input
          name="adressCli"
          placeholder="Adresse"
          value={formData.adressCli}
          onChange={handleChange}
          required
          className="form-input"
        />
        <input
          name="telCli"
          placeholder="Téléphone"
          value={formData.telCli}
          onChange={handleChange}
          required
          className="form-input"
        />
        <input
          name="sexe"
          placeholder="Sexe (H/F)"
          value={formData.sexe}
          onChange={handleChange}
          required
          className="form-input"
        />

        <div className="btn-group">
          <button type="submit" className="btn-submit">
            {isEditing ? 'Modifier' : 'Ajouter'}
          </button>

          {isEditing && (
            <button type="button" onClick={handleDelete} className="btn-delete">
              Supprimer
            </button>
          )}
        </div>
      </form>

      {error && <p className="error-msg">{error}</p>}
    </div>
  );
};

export default ClientForm;
